import React from "react";

function TeacherCard({ img, name, degree, experience }) {
  return (
    <div className="flex flex-col items-center text-center p-4 rounded-xl border shadow hover:shadow-lg transition">
      <img
        src={img}
        alt={name}
        className="w-28 h-28 object-cover rounded-full mb-3 border-2 border-indigo-200"
      />
      <h2 className="font-semibold text-base">{name}</h2>
      <p className="text-gray-500 text-sm">{degree}</p>
      <span className="mt-2 text-xs bg-blue-100 text-blue-700 px-3 py-1 rounded-full font-medium">
        {experience}
      </span>
    </div>
  );
}

export default TeacherCard;
